        setMovies((prev) => (offset === 0 ? arr : [...prev, ...arr]));
        offsetRef.current = offset + arr.length;
        // 반환된 수가 PAGE_SIZE보다 적으면 마지막 페이지
        setHasMore(arr.length === PAGE_SIZE);
      })
      .catch(() => {})
      .finally

